import React, { useState } from 'react';
import { 
  Box, 
  List, 
  ListItem, 
  ListItemIcon, 
  ListItemText,
  IconButton,
  Button,
  Menu,
  MenuItem,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Typography,
  Breadcrumbs,
  Link,
  useTheme
} from '@mui/material';
import {
  InsertDriveFile as FileIcon,
  Folder as FolderIcon,
  MoreVert as MoreIcon,
  Delete as DeleteIcon,
  CloudUpload as UploadIcon,
  ArrowUpward as ArrowUpwardIcon
} from '@mui/icons-material';
import { deletePath } from '../services/api';
import * as api from '../services/api';

const FilePanel = ({ files = [], onFileSelect, onUploadClick, onFileChange }) => {
  const theme = useTheme();
  const [contextMenu, setContextMenu] = useState(null);
  const [selectedFile, setSelectedFile] = useState(null);
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [currentPath, setCurrentPath] = useState('');

  const handleContextMenu = (event, file) => {
    event.preventDefault();
    event.stopPropagation();
    setContextMenu({
      mouseX: event.clientX - 2,
      mouseY: event.clientY - 4,
    });
    setSelectedFile(file);
  };

  const handleClose = () => {
    setContextMenu(null);
    setSelectedFile(null);
  };

  const handleDelete = async () => {
    if (!selectedFile) return;

    try {
      await deletePath(selectedFile.path);
      onFileChange();
    } catch (error) {
      console.error('Failed to delete file:', error);
    }
    setDeleteConfirmOpen(false);
    handleClose();
  };

  const handleDeleteClick = () => {
    setDeleteConfirmOpen(true);
    setContextMenu(null);
  };

  const handleFileClick = async (file) => {
    if (file.type === 'directory') {
      setCurrentPath(file.path);
    } else {
      try {
        console.log('Reading file:', file.path);
        const response = await api.readFile(file.path);
        const language = getFileLanguage(file.name);
        console.log('File read response:', response);

        if (!response || !response.content) {
          throw new Error('Invalid file content received');
        }

        onFileSelect({
          ...file,
          content: response.content,
          language
        });
      } catch (error) {
        console.error('Failed to read file:', error);
        // TODO: Add error notification here
      }
    }
  };

  const getFileLanguage = (filename) => {
    const ext = filename.split('.').pop().toLowerCase();
    const languageMap = {
      'js': 'javascript',
      'jsx': 'javascript',
      'ts': 'typescript',
      'tsx': 'typescript',
      'py': 'python',
      'java': 'java',
      'cpp': 'cpp',
      'c': 'c',
      'html': 'html',
      'css': 'css',
      'json': 'json',
      'md': 'markdown',
    };
    return languageMap[ext] || 'plaintext';
  };

  const handleParentClick = () => {
    if (!currentPath) return;
    const parentPath = currentPath.split('/').slice(0, -1).join('/');
    setCurrentPath(parentPath);
  };

  const getCurrentFiles = () => {
    return files.filter(file => {
      const filePath = file.path.split('/');
      const fileName = filePath.pop();
      const fileDir = filePath.join('/');
      return fileDir === currentPath;
    });
  };

  const renderBreadcrumbs = () => {
    const paths = currentPath.split('/').filter(Boolean);
    return (
      <Box sx={{ p: 1, borderBottom: 1, borderColor: 'divider' }}>
        <Breadcrumbs>
          <Link
            component="button"
            variant="body2"
            onClick={() => setCurrentPath('')}
            sx={{ cursor: 'pointer', textDecoration: 'none' }}
          >
            Root
          </Link>
          {paths.map((name, index) => {
            const path = paths.slice(0, index + 1).join('/');
            return (
              <Link
                key={path}
                component="button"
                variant="body2"
                onClick={() => setCurrentPath(path)}
                sx={{ cursor: 'pointer', textDecoration: 'none' }}
              >
                {name}
              </Link>
            );
          })}
        </Breadcrumbs>
      </Box>
    );
  };

  return (
    <Box sx={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      <Box sx={{ p: 0.5, borderBottom: 1, borderColor: 'divider' }}>
        <Button
          fullWidth
          variant="contained"
          size="small"
          startIcon={<UploadIcon />}
          onClick={onUploadClick}
        >
          Upload
        </Button>
      </Box>

      {renderBreadcrumbs()}

      <List sx={{ 
        flexGrow: 1, 
        overflow: 'auto',
        '& .MuiListItem-root': {
          p: 0.5,
          minHeight: 36
        }
      }}>
        {currentPath && (
          <ListItem
            button
            onClick={handleParentClick}
          >
            <ListItemIcon sx={{ minWidth: 32 }}>
              <ArrowUpwardIcon fontSize="small" />
            </ListItemIcon>
            <ListItemText 
              primary=".."
              primaryTypographyProps={{ 
                variant: 'body2',
                sx: { color: 'text.secondary' }
              }}
            />
          </ListItem>
        )}

        {getCurrentFiles().map((file) => (
          <ListItem
            key={file.path}
            button
            onClick={() => handleFileClick(file)}
            onContextMenu={(e) => handleContextMenu(e, file)}
          >
            <ListItemIcon sx={{ minWidth: 32 }}>
              {file.type === 'directory' ? (
                <FolderIcon fontSize="small" sx={{ color: theme.palette.primary.main }} />
              ) : (
                <FileIcon fontSize="small" />
              )}
            </ListItemIcon>
            <ListItemText 
              primary={file.name}
              primaryTypographyProps={{ 
                variant: 'body2',
                sx: { 
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  whiteSpace: 'nowrap'
                }
              }}
            />
            <IconButton
              edge="end"
              size="small"
              onClick={(e) => {
                e.stopPropagation();
                handleContextMenu(e, file);
              }}
              sx={{ 
                opacity: 0,
                transition: 'opacity 0.2s',
                '.MuiListItem-root:hover &': {
                  opacity: 1
                }
              }}
            >
              <MoreIcon fontSize="small" />
            </IconButton>
          </ListItem>
        ))}
      </List>

      <Menu
        open={contextMenu !== null}
        onClose={handleClose}
        anchorReference="anchorPosition"
        anchorPosition={
          contextMenu !== null
            ? { top: contextMenu.mouseY, left: contextMenu.mouseX }
            : undefined
        }
      >
        <MenuItem onClick={handleDeleteClick} dense>
          <ListItemIcon>
            <DeleteIcon fontSize="small" />
          </ListItemIcon>
          <ListItemText>Delete</ListItemText>
        </MenuItem>
      </Menu>

      <Dialog
        open={deleteConfirmOpen}
        onClose={() => setDeleteConfirmOpen(false)}
      >
        <DialogTitle>Delete File</DialogTitle>
        <DialogContent>
          <Typography>
            Delete "{selectedFile?.name}"?
          </Typography>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setDeleteConfirmOpen(false)}>Cancel</Button>
          <Button onClick={handleDelete} color="error">Delete</Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default FilePanel;
